#include "stm32f10x_gpio.h"
#include "stm32f10x_adc.h"
#include "delay.h"
#include "lcd16x2.h"
#include <stdio.h>

uint16_t ADC1_Read(void);

uint16_t adcValue;
char sAdcValue[5];

int main(void)
{
 DelayInit();
 lcd16x2_init(LCD16X2_DISPLAY_ON_CURSOR_OFF_BLINK_OFF);

// Initialize ADC
 ADC1_Init();

while (1)
 {
 // Read ADC value
 adcValue = ADC1_Read();
 // Convert ADC value to string
 sprintf(sAdcValue, "%i", adcValue);
 // Display ADC value to LCD
 lcd16x2_clrscr();
 lcd16x2_puts(sAdcValue);

DelayMs(500);
 }
}

void ADC1_Init()
{
 // Initialization struct
 ADC_InitTypeDef ADC_InitStruct;
 GPIO_InitTypeDef GPIO_InitStruct;

// Step 1: Initialize ADC1
 RCC_APB2PeriphClockCmd(RCC_APB2Periph_ADC1, ENABLE);
 ADC_InitStruct.ADC_ContinuousConvMode = DISABLE;
 ADC_InitStruct.ADC_DataAlign = ADC_DataAlign_Right;
 ADC_InitStruct.ADC_ExternalTrigConv = DISABLE;
 ADC_InitStruct.ADC_ExternalTrigConv = ADC_ExternalTrigConv_None;
 ADC_InitStruct.ADC_Mode = ADC_Mode_Independent;
 ADC_InitStruct.ADC_NbrOfChannel = 1;
 ADC_InitStruct.ADC_ScanConvMode = DISABLE;
 ADC_Init(ADC1, &ADC_InitStruct);
 ADC_Cmd(ADC1, ENABLE);
 // Select input channel for ADC1
 // ADC1 channel 0 (PA0)
 ADC_RegularChannelConfig(ADC1, ADC_Channel_0, 1, ADC_SampleTime_55Cycles5);

// Step 2: Initialize GPIOA (PA0)
 RCC_APB2PeriphClockCmd(RCC_APB2Periph_GPIOA, ENABLE);
 GPIO_InitStruct.GPIO_Pin = GPIO_Pin_0;
 GPIO_InitStruct.GPIO_Mode = GPIO_Mode_AIN;
 GPIO_Init(GPIOA, &GPIO_InitStruct);
}

uint16_t ADC1_Read()
{
 // Start ADC conversion
 ADC_SoftwareStartConvCmd(ADC1, ENABLE);
 // Wait until ADC conversion finished
 while (!ADC_GetFlagStatus(ADC1, ADC_FLAG_EOC));

return ADC_GetConversionValue(ADC1);
}

